 313 |         .viewer-overlay.active { transform: translateX(0); }
 314 |         .viewer-header {
 315 |             min-height: 60px; height: auto; padding: 10px 16px; border-bottom: 1px solid var(--border);
 316 |             display: flex; align-items: center; justify-content: space-between;
 317 |             gap: 12px; background: var(--card-bg); flex-shrink: 0;
 318 |             overflow-x: auto; scrollbar-width: none;
 319 |             -webkit-overflow-scrolling: touch;
 320 |         }
 321 |         .viewer-header::-webkit-scrollbar { display: none; }
 322 |         .viewer-header > * { flex-shrink: 0; }
 323 |         .viewer-title { font-weight: 600; font-size: 14px; font-family: 'JetBrains Mono', monospace; }
 324 |         #ace-container { flex: 1; width: 100%; position: relative; }
 325 | 
 326 |         /* PREVIEW TAB */
 327 |         .browser-toolbar {
 328 |             display: flex; gap: 8px; padding: 8px 12px; background: #1a1a1c; border: 1px solid var(--border);
 329 |             border-radius: 12px; margin-bottom: 12px; align-items: center;
 330 |         }
 331 |         .url-bar {
 332 |             flex: 1; background: #0a0a0a; border: 1px solid #333; color: #eee; padding: 6px 12px;
 333 |             border-radius: 8px; font-size: 12px; outline: none; font-family: 'JetBrains Mono';
