2252 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2253 |     function applyLocalPatch(content, ops) {
2254 |         let lines = content.split('\n');
2255 |         let logs = [];
2256 |         let success = true;
2257 | 
2258 |         if (typeof ops === 'string') {
2259 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2260 |         }
2261 | 
2262 |         ops.forEach(op => {
2263 |             if (op.action === 'comment') return;
2264 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2265 |             
2266 |             if (op.action === 'replace_block') {
2267 |                 // Strategy 1: Exact String Match (Fastest)
2268 |                 const currentStr = lines.join('\n');
2269 |                 if (currentStr.includes(op.find_block)) {
2270 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2271 |                     logs.push('Exact match applied');
2272 |                     return;
2273 |                 }
2274 | 
2275 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2276 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2277 |                 if (searchLines.length === 0) return;
2278 | 
2279 |                 let matchStart = -1;
2280 |                 let matchEnd = -1;
2281 | 
2282 |                 // Scan file lines
2283 |                 for (let i = 0; i < lines.length; i++) {
2284 |                     // If first line matches (ignoring whitespace)
2285 |                     if (lines[i].trim() === searchLines[0]) {
2286 |                         // Check subsequent lines
2287 |                         let allMatch = true;
2288 |                         let fileOffset = 0;
2289 |                         let searchOffset = 1;
2290 |                         
2291 |                         while (searchOffset < searchLines.length) {
2292 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2293 |                             const nextFile = lines[i + fileOffset + 1].trim();
2294 |                             // Skip empty lines in file if they aren't in search block
2295 |                             if (nextFile === '') {
2296 |                                 fileOffset++;
2297 |                                 continue;
2298 |                             }
2299 |                             if (nextFile !== searchLines[searchOffset]) {
2300 |                                 allMatch = false;
2301 |                                 break;
2302 |                             }
2303 |                             fileOffset++;
2304 |                             searchOffset++;
2305 |                         }
2306 | 
2307 |                         if (allMatch) {
2308 |                             matchStart = i;
2309 |                             matchEnd = i + fileOffset;
2310 |                             break;
2311 |                         }
2312 |                     }
2313 |                 }
2314 | 
2315 |                 if (matchStart !== -1) {
2316 |                     // Replace the range of lines
2317 |                     const replacement = op.replace_with.split('\n');
2318 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2319 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2320 |                 } else {
2321 |                     success = false;
2322 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2323 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2324 |                 }
2325 |             }
2326 |         });
2327 |         return { content: lines.join('\n'), success, logs };
2328 |     }
