4327 |     async function openSyntaxReport(path, error) {
4328 |         const modal = document.getElementById('syntax-report-modal');
4329 |         const pathEl = document.getElementById('sr-path');
4330 |         const msgEl = document.getElementById('sr-message');
4331 |         const codeEl = document.getElementById('sr-code');
4332 |         const fixBtn = document.getElementById('btn-auto-fix-wasm');
4333 |         
4334 |         pathEl.innerText = path;
4335 |         msgEl.innerHTML = `<strong>Line ${error.line}, Col ${error.column || '?'}:</strong> ${error.message}`;
4336 |         codeEl.innerText = "Loading context...";
4337 |         modal.style.display = 'flex';
4338 |         fixBtn.style.display = 'none'; // Hide until we verify deterministic fix
4339 | 
4340 |         // Fetch File Content
4341 |         try {
4342 |             const res = await fetch(CONFIG.funcUrl, { 
4343 |                 method: 'POST', headers: {'Content-Type': 'application/json'}, 
4344 |                 body: apiBody({ action: 'preview_file', file_path: path }) 
4345 |             });
4346 |             const data = await res.json();
4347 |             const fullCode = b64DecodeUnicode(data.content || "");
4348 |             
4349 |             // Window: 5 lines before and after
4350 |             const lines = fullCode.split('\n');
4351 |             const start = Math.max(0, error.line - 6);
4352 |             const end = Math.min(lines.length, error.line + 5);
4353 |             
4354 |             let snippet = "";
4355 |             for (let i = start; i < end; i++) {
4356 |                 const lineNum = i + 1;
4357 |                 const marker = (lineNum === error.line) ? "> " : "  ";
4358 |                 snippet += `${marker}${lineNum.toString().padEnd(4)} | ${lines[i]}\n`;
4359 |             }
4360 |             
4361 |             codeEl.innerText = snippet;
4362 |             
4363 |             // Store for fix application
4364 |             currentSyntaxContext = { file: path, error: error, code: fullCode, ops: null };
4365 | 
4366 |             // Check for Deterministic Fix Availability
4367 |             checkDeterministicFix(path, error, fullCode);
4368 | 
4369 |         } catch(e) {
4370 |             codeEl.innerText = "Failed to load file content: " + e.message;
4371 |         }
4372 |     }
