5160 |     function formatBytes(bytes) {
5161 |         if (!bytes) return '0 B';
5162 |         const k = 1024;
5163 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5164 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5165 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5166 |     }
