5168 |     function timeAgo(dateString) {
5169 |         const date = new Date(dateString);
5170 |         const now = new Date();
5171 |         const seconds = Math.floor((now - date) / 1000);
5172 |         if (seconds < 10) return 'just now';
5173 |         if (seconds < 60) return seconds + 's ago';
5174 |         const minutes = Math.floor(seconds / 60);
5175 |         if (minutes < 60) return minutes + 'm ago';
5176 |         const hours = Math.floor(minutes / 60);
5177 |         if (hours < 24) return hours + 'h ago';
5178 |         return date.toLocaleDateString();
5179 |     }
