5381 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5382 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5383 |         
5384 |         const navItems = document.querySelectorAll('.nav-item');
5385 |         switchTab(tabId, navItems[navIndex]);
5386 | 
5387 |         const scrollContainer = document.querySelector('.main-view');
5388 |         let retryCount = 0;
5389 |         const MAX_RETRIES = 5;
5390 | 
5391 |         const attemptNavigation = async () => {
5392 |             const element = document.querySelector(selector);
5393 |             
5394 |             if (element) {
5395 |                 console.log("[DeepJump] Element found. Scrolling...");
5396 |                 
5397 |                 // Wait for any tab transition animations
5398 |                 await new Promise(r => setTimeout(r, 300));
5399 | 
5400 |                 let offsetTop = 0;
5401 |                 let curr = element;
5402 |                 while (curr && curr !== scrollContainer) {
5403 |                     offsetTop += curr.offsetTop;
5404 |                     curr = curr.offsetParent;
5405 |                 }
5406 | 
5407 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5408 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5409 | 
5410 |                 // Visual Highlight
5411 |                 element.style.transition = 'all 0.5s ease';
5412 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5413 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5414 |                 setTimeout(() => {
5415 |                     element.style.backgroundColor = '';
5416 |                     element.style.boxShadow = '';
5417 |                 }, 3000);
5418 |                 
5419 |                 console.groupEnd();
5420 |                 return true;
5421 |             }
5422 | 
5423 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5424 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5425 |                 retryCount++;
5426 |                 showGlobalToast("🔍 Searching deeper...");
5427 |                 
5428 |                 await loadMoreFn(); 
5429 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5430 |                 return attemptNavigation();
5431 |             }
5432 | 
5433 |             console.error("[DeepJump] Failed: Element not found after retries.");
5434 |             showGlobalToast("Entry not found in recent history.", true);
5435 |             console.groupEnd();
5436 |             return false;
5437 |         };
5438 | 
5439 |         setTimeout(attemptNavigation, 100);
5440 |     }
