7814 |     function extractTableNames(sql) {
7815 |         if (!sql) return [];
7816 |         const tables = [];
7817 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7818 |         
7819 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7820 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7821 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7822 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7823 | 
7824 |         let match;
7825 |         while ((match = fromRegex.exec(sql)) !== null) {
7826 |             const name = match[1];
7827 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7828 |                 tables.push(name);
7829 |             }
7830 |         }
7831 |         
7832 |         while ((match = metaRegex.exec(sql)) !== null) {
7833 |             const name = match[1];
7834 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7835 |                 tables.push(name);
7836 |             }
7837 |         }
7838 | 
7839 |         return tables;
7840 |     }
7841 | 
7842 |     function convertToCSV(resultObj) {
7843 |         const data = resultObj.data || [];
7844 |         if (!data.length) return '';
7845 |         
7846 |         const tables = extractTableNames(resultObj.sql);
7847 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7848 | 
7849 |         const headers = Object.keys(data[0]);
7850 |         const rows = data.map(row => 
7851 |             headers.map(header => {
7852 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7853 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7854 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7855 |             }).join(',')
7856 |         );
7857 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7858 |     }
